import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Constructor;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testParse_withValidReader_shouldReturnCSVParser() throws Exception {
        Reader mockReader = mock(Reader.class);

        // Use reflection to create a spy on CSVParser instance
        Constructor<CSVParser> constructor = CSVParser.class.getDeclaredConstructor(Reader.class, CSVFormat.class);
        constructor.setAccessible(true);
        CSVParser realParser = constructor.newInstance(mockReader, csvFormat);
        CSVParser spyParser = spy(realParser);

        // Spy on CSVFormat instance
        CSVFormat spyFormat = spy(csvFormat);
        // Mock parse(Reader) method to return spyParser
        doReturn(spyParser).when(spyFormat).parse(any(Reader.class));

        CSVParser parser = spyFormat.parse(mockReader);
        assertNotNull(parser);
        assertSame(spyParser, parser);
    }

    @Test
    void testParse_withNullReader_shouldThrowNullPointerException() {
        assertThrows(NullPointerException.class, () -> {
            csvFormat.parse(null);
        });
    }
}
